private static PixelBuffer[] ProcessMultiImpl(PixelBuffer?[] inputs, IReadOnlyDictionary<string, object> parameters, PixelGraphContext context)
{
    var source = inputs.Length > 0 ? inputs[0] : null;
    var target = inputs.Length > 1 ? inputs[1] : null;
    var size = context.TileSize;

    if (source is null && target is null)
    {
        var empty = PixelBuffer.CreateSolid(size, size, 0, 0, 0);
        return [empty, empty.Clone()];
    }
    if (source is null)
        return [target!.Clone(), PixelBuffer.CreateSolid(size, size, 0, 0, 0)];
    if (target is null)
        return [source.Clone(), PixelBuffer.CreateSolid(size, size, 1, 1, 1)];

    var blend = GetFloat(parameters, "blend", 0.5f);
    var mode = GetChoice(parameters, "mode", "crossFade");

    var image = new PixelBuffer(size, size);
    var mask = new PixelBuffer(size, size);
    var invSize = 1f / size;

    image.ParallelForEachPixel((x, y) =>
    {
        var (sr, sg, sb, sa) = source.GetPixelWrapped(x, y);
        var (tr, tg, tb, ta) = target.GetPixelWrapped(x, y);

        float blendFactor;
        switch (mode)
        {
            case "dissolve":
            {
                // Per-pixel hash-based dissolve: switch from source to target when hash > blend
                var hash = HashToUnit(x * 7 + y * 13, y * 11 + x * 5, 42);
                blendFactor = hash < blend ? 1f : 0f;
                break;
            }
            case "slide":
            {
                // Horizontal slide: split line at blend position
                var splitPos = blend * size;
                blendFactor = x < splitPos ? 1f : 0f;
                // Smooth edge (2-pixel transition)
                if (x >= splitPos - 1f && x < splitPos + 1f)
                    blendFactor = (x - splitPos + 1f) * 0.5f;
                break;
            }
            default: // crossFade
            {
                blendFactor = blend;
                break;
            }
        }

        blendFactor = Math.Clamp(blendFactor, 0f, 1f);

        // Blend channels
        var outR = Lerp(sr, tr, blendFactor);
        var outG = Lerp(sg, tg, blendFactor);
        var outB = Lerp(sb, tb, blendFactor);
        var outA = Lerp(sa, ta, blendFactor);

        image.SetPixel(x, y,
            Math.Clamp(outR, 0f, 1f),
            Math.Clamp(outG, 0f, 1f),
            Math.Clamp(outB, 0f, 1f),
            Math.Clamp(outA, 0f, 1f));

        // Mask: blend weight as grayscale
        mask.SetPixel(x, y, blendFactor, blendFactor, blendFactor, 1f);
    });

    return [image, mask];
    }
